var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"보름 뒤","JPN":"2週間後","ENG":"15 days later","TWN":"半個月後","SCN":"半个月后","DEU":"15 days later","FRA":"15 days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>","TWN":"管理局直轄市<color=#ffd34c>查雷德</color>","SCN":"管理局直辖城市<color=#ffd34c>查雷德</color>","DEU":"Administration Direct Control City, <color=#ffd34c>Charade</color>","FRA":"Administration Direct Control City, <color=#ffd34c>Charade</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"말씀하신 곳에 거의 도착했습니다만.","JPN":"目的地まであともう少しですが。","ENG":"We've almost arrived at the destination you requested.","TWN":"就快抵達你說的目的地了。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"대낮부터 이런 곳에서 데이트라니 취향이 참 독특하시네요.","JPN":"真っ昼間からこのような場所でデートだなんて、独特ですね。","ENG":"Having a date in a place like this in broad daylight? That's some questionable taste you got there.","TWN":"大白天的在這種地方約會，你的喜好很特別呢。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하, 하하. 그게…… 데이트는 아닌데요.","JPN":"は、はは。それが……デートはないのよ。","ENG":"Hah... Hah hah. Well... It's not a date.","TWN":"哈哈……這不是約會啦。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"죄송해요. 사장님. 괜한 오해를 불러일으켜서.","JPN":"申し訳ありません、社長。変な誤解を招いてしまいまして。","ENG":"I'm sorry for causing a misunderstanding, Boss.","TWN":"老闆抱歉，引起不必要的誤會。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나는 괜찮다네.","JPN":"私は大丈夫だ。","ENG":"It's all right with me.","TWN":"我是無所謂。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 이곳에서 소개해 줄 사람이 있다는 말은…….","JPN":"それより、ここで私に紹介したいという者は……","ENG":"Anyway, who is this person you wanted to introduce me to...?","TWN":"倒是你說要介紹一個人給我認識……"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"안녕하세요, 브라운 씨.","JPN":"こんにちは、ブラウンさん。","ENG":"Hello, Mr. Brown.","TWN":"你好，布朗先生！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"오늘도 친구분을 보러 오셨군요, 말레나 스키너.","JPN":"今日もお友達に会いに来たんですね、マレーナ・スキナー。","ENG":"I see you came to see your friend again, Malena Skinner.","TWN":"今天又來看朋友了啊，瑪蓮娜·史金納。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 매일 찾아오는 동료가 있다니, 그분도 쓸쓸하지는 않을 겁니다.","JPN":"こうやって毎日訪ねる仲間がいたら、あの方も寂しい思いはしないでしょうね。","ENG":"Having a colleague who visits every day. I'm sure he won't be lonely.","TWN":"每天都有像你這樣的同伴來探望，那位朋友也不會感到孤單了。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"그런데 옆에 계신 신사분은……?","JPN":"ところで、隣の方は……？","ENG":"But who is the gentleman next to you...?","TWN":"不過，旁邊的這位先生是……？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아, 저희 사장님이세요.","JPN":"あ、うちの社長です。","ENG":"Oh, this is my boss.","TWN":"啊，這是我們的老闆。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"카나리아 스쿼드, 그 소문의 코치시로군요. 당사자를 직접 보게 될 줄은 몰랐네요.","JPN":"カナリア・スクワッド、あのウワサのコーチですね。直接ご本人にお会いできるとは。","ENG":"So, you are the rumored coach of the Canary Squad. I never imagined that I'd see you in person.","TWN":"原來金絲雀小隊傳聞中的教練是你啊。沒想到能親眼見到本人。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"내노라 하는 샤레이드의 강팀들을 차례로 쓰러트리고 있다죠?","JPN":"数あるシャレードの強豪を次々と倒しているらしいではないですか。","ENG":"I heard you defeated all the powerful teams in Charade.","TWN":"聽說你們把那些查雷德強隊一個個地都擊敗了？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 고맙네. 응원이라면 감사히 받지.","JPN":"はは、嬉しいな。応援ならありがたく受け取ろう。","ENG":"Haha, I'm flattered. Thank you for cheering us on.","TWN":"哈哈，謝謝你。你的支持我欣然接受。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저…….","JPN":"あの……","ENG":"Um...","TWN":"呃……"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"아하, 이거 아무래도 시간을 빼앗은 모양이군요.","JPN":"ああ、すみません。つい待たせてしまいましたね。","ENG":"A-ha, it seems I have taken too much of your time.","TWN":"啊哈，看起來是佔用了你們的時間啊。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"여기 묘역 방문 허가증입니다. 요즘 치안이 영 좋지 않아서 말이죠.","JPN":"どうぞ、お墓の訪問許可証です。最近治安がよくなくて。","ENG":"Here is your cemetery visitor's pass. It's because the security around here recently hasn't been so good.","TWN":"拿著，這是墓園訪問許可證。最近治安不太好。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"감사합니다. 브라운 씨.","JPN":"ありがとうございます、ブラウンさん。","ENG":"Thank you, Mr. Brown.","TWN":"非常感謝，布朗先生。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼…….","JPN":"それでは……","ENG":"Then...","TWN":"那我們就……"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CEMETRY_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 저도 슬슬 다음을 준비할 때로군요.","JPN":"では、私もそろそろ次の準備に移らないと。","ENG":"Then, I think it's time I prepared for the next one.","TWN":"那麼，我也該準備下一步了。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"CEMETRY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};